using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;public class AuditServiceTests_SyncFromBlockchain_WithFakeId_ShouldReturnErrorMessage : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {    "AuthService",    "AuditService"    };    [SkippableFact]    public async Task SyncFromBlockchain_WithFakeId_ShouldReturnErrorMessage()    {    await AuthenticateAsAdminAsync(AuditClient);    var response = await PostWithRetryAsync(AuditClient, ApiEndpoints.Audit.SyncFromBlockchain("fake-blockchain-id"), null);        var json = await ReadJsonResponseAsync(response);    Assert.False(string.IsNullOrEmpty(json.GetProperty("message").GetString()));    }}
